public class SearchString {
 public static int searchString(String mainString, String searchString) {
 return mainString.indexOf(searchString);
 }

 public static void main(String[] args) {
 String mainString = "Hello, Advanced Java!";
 String searchString = "Advanced";
 int index = searchString(mainString, searchString);
 System.out.println("Index of first occurrence: " + index);
 }
}

public class SearchStringFromIndex {
 public static int searchStringFromIndex(String mainString, String searchString, int fromIndex) {
 return mainString.indexOf(searchString, fromIndex);
 }

 public static void main(String[] args) {
 String mainString = "Hello, Advanced Java!";
 String searchString = "a";
 int fromIndex = 10;
 int index = searchStringFromIndex(mainString, searchString, fromIndex);
 System.out.println("Index of first occurrence from index " + fromIndex + ": " + index);
 }
}
